/**
 * Storefront Worker
 *
 * Routes {store}.tarai.space requests to the right store.
 * KV cache for 95% of requests (~10ms).
 * On cache miss: read layout from Turso, render HTML, cache, serve.
 */

import { renderStorefront } from './renderer';
import { SECTION_RENDERERS } from './sections';
import type { StorefrontLayout } from './schema';

export interface Env {
  STOREFRONT_CACHE: KVNamespace;
  TURSO_URL: string;
  TURSO_AUTH_TOKEN: string;
}

export default {
  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
    const url = new URL(request.url);
    const host = url.hostname;

    // Extract store subdomain: {store}.tarai.space
    const storeMatch = host.match(/^([a-z0-9-]+)\.tarai\.space$/);
    if (!storeMatch) {
      return new Response('Not found', { status: 404 });
    }

    const storeSlug = storeMatch[1];
    const isPreview = url.pathname === '/preview';

    try {
      // 1. Check KV cache (skip for preview)
      if (!isPreview) {
        const cached = await env.STOREFRONT_CACHE.get(`html:${storeSlug}`);
        if (cached) {
          return new Response(cached, {
            headers: { 'Content-Type': 'text/html; charset=utf-8' },
          });
        }
      }

      // 2. Read layout from Turso
      const layout = await readLayout(env, storeSlug);
      if (!layout) {
        return new Response('Store not found', { status: 404 });
      }

      // 3. Read products from Turso
      const products = await readProducts(env, storeSlug);

      // 4. Render HTML
      const html = await renderStorefront(layout, storeSlug, products);

      // 5. Cache in KV (5min TTL, skip for preview)
      if (!isPreview) {
        ctx.waitUntil(
          env.STOREFRONT_CACHE.put(`html:${storeSlug}`, html, { expirationTtl: 300 })
        );
      }

      // 6. Serve
      return new Response(html, {
        headers: {
          'Content-Type': 'text/html; charset=utf-8',
          'Cache-Control': isPreview ? 'no-cache' : 'public, max-age=300',
        },
      });
    } catch (err: any) {
      console.error(`[Storefront] Error for ${storeSlug}:`, err);
      return new Response('Internal error', { status: 500 });
    }
  },
};

/**
 * Read the published layout for a store from Turso.
 * Falls back to draft if no published version exists.
 */
async function readLayout(env: Env, storeSlug: string): Promise<StorefrontLayout | null> {
  const result = await tursoQuery(
    env,
    `SELECT data FROM matter
     WHERE form IN (SELECT id FROM form WHERE data LIKE ? AND type = 'store' AND active = 1)
     AND type = 'storefront_published' AND active = 1
     LIMIT 1`,
    [`%"subdomain":"${storeSlug}"%`]
  );

  if (result.rows?.length) {
    try {
      return JSON.parse(result.rows[0].data as string);
    } catch {}
  }

  // Fallback to draft
  const draft = await tursoQuery(
    env,
    `SELECT data FROM matter
     WHERE form IN (SELECT id FROM form WHERE data LIKE ? AND type = 'store' AND active = 1)
     AND type = 'storefront_draft' AND active = 1
     LIMIT 1`,
    [`%"subdomain":"${storeSlug}"%`]
  );

  if (draft.rows?.length) {
    try {
      return JSON.parse(draft.rows[0].data as string);
    } catch {}
  }

  return null;
}

/**
 * Read products for a store from Turso.
 */
async function readProducts(env: Env, storeSlug: string): Promise<Array<{ name: string; price: number | null; imageUrl?: string }>> {
  const result = await tursoQuery(
    env,
    `SELECT f.title, m.value, m.data
     FROM matter m
     JOIN graph g ON g.src = m.id AND g.type = 'belongs_to'
     JOIN form f ON f.id = m.form
     JOIN form store ON store.id = g.tgt
     WHERE store.data LIKE ? AND store.type = 'store' AND store.active = 1
     AND m.type = 'stock' AND m.active = 1`,
    [`%"subdomain":"${storeSlug}"%`]
  );

  return (result.rows || []).map((row: any) => {
    let imageUrl: string | undefined;
    try {
      const data = JSON.parse(row.data || '{}');
      imageUrl = data.imageUrl;
    } catch {}
    return {
      name: row.title || 'Item',
      price: row.value ?? null,
      imageUrl,
    };
  });
}

/**
 * Execute a query against Turso.
 */
async function tursoQuery(
  env: Env,
  sql: string,
  args: any[] = []
): Promise<{ rows: any[] }> {
  const res = await fetch(env.TURSO_URL, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${env.TURSO_AUTH_TOKEN}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ sql, args }),
  });

  if (!res.ok) {
    const body = await res.text().catch(() => '');
    throw new Error(`Turso query failed (${res.status}): ${body.slice(0, 200)}`);
  }

  return res.json();
}
